import{E as e,R as t,_ as n,h as r,pt as i,x as a,z as o}from"./runtime-core.esm-bundler-ChtuvW5g.js";var s={class:`ant-doc vp-doc`},c=a({__name:`llms.zh-CN`,setup(a,{expose:c}){let l={title:`LLMs.txt`,frontmatter:{title:`LLMs.txt`,tag:`New`},headers:[{level:2,title:`什么是 LLMs.txt？`,slug:`什么是-llms-txt`,link:`#什么是-llms-txt`,children:[]},{level:2,title:`可用资源`,slug:`可用资源`,link:`#可用资源`,children:[]},{level:2,title:`在 AI 工具中的使用`,slug:`在-ai-工具中的使用`,link:`#在-ai-工具中的使用`,children:[{level:3,title:`Cursor`,slug:`cursor`,link:`#cursor`,children:[]},{level:3,title:`Windsurf`,slug:`windsurf`,link:`#windsurf`,children:[]},{level:3,title:`Claude Code`,slug:`claude-code`,link:`#claude-code`,children:[]},{level:3,title:`Gemini CLI`,slug:`gemini-cli`,link:`#gemini-cli`,children:[]},{level:3,title:`Trae`,slug:`trae`,link:`#trae`,children:[]},{level:3,title:`Qoder`,slug:`qoder`,link:`#qoder`,children:[]},{level:3,title:`其他 AI 工具`,slug:`其他-ai-工具`,link:`#其他-ai-工具`,children:[]}]}],description:``},u={title:`LLMs.txt`,tag:`New`},d=i({});o(`__pageData__`,e=>{d.value=e});let f=e(`__pageData__`,null);return f&&f(l),o(`__pageInfo__`,l),c({frontmatter:u,pageData:l}),(e,i)=>(t(),r(`div`,s,[...i[0]||=[n(`<p>本指南介绍如何让 Cursor、Windsurf 和 Claude 等 AI 工具更好地理解 ProComponents of Vue。</p><h2 id="什么是-llms-txt" tabindex="-1">什么是 LLMs.txt？ <a class="header-anchor" href="#什么是-llms-txt" aria-label="Permalink to &quot;什么是 LLMs.txt？&quot;">​</a></h2><p>我们支持通过 <a href="https://llmstxt.org/">LLMs.txt</a> 文件向大语言模型（LLMs）提供 ProComponents of Vuents of Vue 文档。此功能可帮助 AI 工具更好地理解我们的组件库、API 及使用模式。</p><h2 id="可用资源" tabindex="-1">可用资源 <a class="header-anchor" href="#可用资源" aria-label="Permalink to &quot;可用资源&quot;">​</a></h2><p>我们提供多个 LLMs.txt 路由来帮助 AI 工具访问文档：</p><ul><li><a href="https://antdv-next.com/llms.txt">llms.txt</a> - 包含所有组件及其文档链接的结构化概览</li><li><a href="https://antdv-next.com/llms-full.txt">llms-full.txt</a> - 提供包含实现细节和示例的完整文档</li></ul><h2 id="在-ai-工具中的使用" tabindex="-1">在 AI 工具中的使用 <a class="header-anchor" href="#在-ai-工具中的使用" aria-label="Permalink to &quot;在 AI 工具中的使用&quot;">​</a></h2><h3 id="cursor" tabindex="-1">Cursor <a class="header-anchor" href="#cursor" aria-label="Permalink to &quot;Cursor&quot;">​</a></h3><p>在 Cursor 中使用 <code>@Docs</code> 功能将 LLMs.txt 文件包含到您的项目中。这有助于 Cursor 为 ProComponents of Vuents of Vue 组件提供更准确的代码建议和文档。</p><p><a href="https://docs.cursor.com/zh/context/@-symbols/@-docs">详细了解 Cursor 中的 @Docs 功能</a></p><h3 id="windsurf" tabindex="-1">Windsurf <a class="header-anchor" href="#windsurf" aria-label="Permalink to &quot;Windsurf&quot;">​</a></h3><p>通过 <code>@</code> 引用或在 <code>.windsurf/rules</code> 文件中配置 LLMs.txt 文件，以增强 Windsurf 对 ProComponents of Vuents of Vue 组件的理解。</p><p><a href="https://docs.windsurf.com/windsurf/cascade/memories">详细了解 Windsurf Memories 功能</a></p><h3 id="claude-code" tabindex="-1">Claude Code <a class="header-anchor" href="#claude-code" aria-label="Permalink to &quot;Claude Code&quot;">​</a></h3><p>在 Claude Code 中，将 <code>LLMs.txt</code> 添加到工作区的知识库（Docs / Context Files）配置中，即可在代码补全与解释时引用其中的内容，从而提升对 ProComponents of Vuents of Vue 组件的理解。</p><p><a href="https://code.claude.com/docs">详细了解 Claude Code 文档上下文配置</a></p><h3 id="gemini-cli" tabindex="-1">Gemini CLI <a class="header-anchor" href="#gemini-cli" aria-label="Permalink to &quot;Gemini CLI&quot;">​</a></h3><p>在 Gemini CLI 中，可以通过 <code>--context</code> 参数或在 <code>.gemini/config.json</code> 中指定 <code>LLMs.txt</code> 文件路径，让 Gemini 在回答和生成代码时参考该文档。</p><p><a href="https://ai.google.dev/gemini-api/docs?hl=zh-cn">详细了解 Gemini CLI 上下文配置</a></p><h3 id="trae" tabindex="-1">Trae <a class="header-anchor" href="#trae" aria-label="Permalink to &quot;Trae&quot;">​</a></h3><p>在 Trae 中，将 <code>LLMs.txt</code> 文件放入项目的 knowledge sources 并在设置里开启引用，即可让 Trae 在生成或分析代码时更好地支持 ProComponents of Vuents of Vue 组件。</p><p><a href="https://trae.ai/docs">详细了解 Trae 的知识源功能</a></p><h3 id="qoder" tabindex="-1">Qoder <a class="header-anchor" href="#qoder" aria-label="Permalink to &quot;Qoder&quot;">​</a></h3><p>在 Qoder 中，可以在 <code>.qoder/config.yml</code> 中添加 <code>LLMs.txt</code> 作为外部知识文件，或在对话中通过 <code>@docs LLMs.txt</code> 进行临时引用，增强对 ProComponents of Vuents of Vue 组件的支持。</p><p><a href="https://docs.qoder.com/">详细了解 Qoder 配置方法</a></p><h3 id="其他-ai-工具" tabindex="-1">其他 AI 工具 <a class="header-anchor" href="#其他-ai-工具" aria-label="Permalink to &quot;其他 AI 工具&quot;">​</a></h3><p>任何支持 LLMs.txt 的 AI 工具均可使用以上路径来更好地理解 ProComponents of Vuents of Vue。</p>`,27)]]))}});export{c as default};